class Solution {
public:
    vector<int> findRedundantDirectedConnection(vector<vector<int>>& e) {
        int n=e.size(); vector<int> par(n+1); vector<int> cand;
        for(auto& ed:e){ if(par[ed[1]]) cand={par[ed[1]],ed[1],ed[0],ed[1]}; else par[ed[1]]=ed[0]; }
        function<bool(int,int)> cyc=[&](int s,int ban)->bool{
            unordered_set<int> vis; int x=s;
            while(x&&!vis.count(x)){ if(x==ban) return false; vis.insert(x); x=par[x]; }
            return x!=0;
        };
        if(!cand.empty()) return cyc(cand[2],cand[3])?vector<int>{cand[0],cand[1]}:vector<int>{cand[2],cand[3]};
        for(int i=n-1;i>=0;i--){ int u=e[i][0],v=e[i][1], old=par[v]; par[v]=0; if(!cyc(u,0)){ return {u,v}; } par[v]=old; }
        return {};
    }
};

